UPDATE user_site target_us INNER JOIN user_site manager_us ON manager_us.site_id = target_us.site_id AND manager_us.user_id = #{managerUserId} AND manager_us.deleted_at IS NULL INNER JOIN site s ON s.site_id = manager_us.site_id AND s.deleted_at IS NULL SET target_us.deleted_at = CURRENT_TIMESTAMP, target_us.updated_at = CURRENT_TIMESTAMP WHERE target_us.user_id = #{userId} AND target_us.deleted_at IS NULL
